// server-src/lib/clipboard.ts
import { spawn } from "child_process";
import os7 from "os";
async function copyToClipboard(text, options = {}) {
  const timeoutMs = options.timeoutMs ?? 2000;
  for (const candidate of clipboardCandidates()) {
    const ok = await runClipboardCandidate(candidate, text, timeoutMs);
    if (ok)
      return true;
  }
  return false;
}
function clipboardCandidates() {
  switch (os7.platform()) {
    case "darwin":
      return [{ name: "pbcopy", args: [] }];
    case "linux":
      return [
        { name: "wl-copy", args: [] },
        { name: "xclip", args: ["-selection", "clipboard"] },
        { name: "xsel", args: ["--clipboard", "--input"] }
      ];
    case "win32":
      return [{ name: "clip.exe", args: [] }];
    default:
      return [];
  }
}
async function runClipboardCandidate(candidate, text, timeoutMs) {
  return new Promise((resolve2) => {
    let child;
    try {
      child = spawn(candidate.name, candidate.args, { stdio: ["pipe", "ignore", "ignore"] });
    } catch {
      resolve2(false);
      return;
    }
    let settled = false;
    const settle = (ok) => {
      if (settled)
        return;
      settled = true;
      resolve2(ok);
    };
    const timer = setTimeout(() => {
      child.kill("SIGKILL");
      settle(false);
    }, timeoutMs);
    child.on("error", () => {
      clearTimeout(timer);
      settle(false);
    });
    child.on("close", (code) => {
      clearTimeout(timer);
      settle(code === 0);
    });
    child.stdin?.on("error", () => {});
    child.stdin?.end(text);
  });
}

// server-src/lib/pluginState.ts
import fsp3 from "fs/promises";
import os8 from "os";
import path12 from "path";
var PluginStateSchema = exports_external.object({
  share_count: exports_external.number().int().nonnegative()
});
var DEFAULT_STATE = {
  share_count: 0
};
function pluginStateFilePath(home = os8.homedir()) {
  return path12.join(home, "Library", "Application Support", "tanagram", "lore", "plugin-state.json");
}
async function readPluginState(home) {
  const p = pluginStateFilePath(home);
  let raw;
  try {
    raw = await fsp3.readFile(p, "utf8");
  } catch (err) {
    if (isEnoent3(err))
      return { ...DEFAULT_STATE };
    throw err;
  }
  let parsed;
  try {
    parsed = JSON.parse(raw);
  } catch (err) {
    throw new Error(`plugin-state file at ${p} is not valid JSON: ${err.message}`);
  }
  const result = PluginStateSchema.safeParse(parsed);
  if (!result.success) {
    throw new Error(`plugin-state file at ${p} failed schema validation: ${result.error.message}`);
  }
  return result.data;
}
async function writePluginState(state, home) {
  const p = pluginStateFilePath(home);
  const parent = path12.dirname(p);
  await fsp3.mkdir(parent, { recursive: true, mode: 448 });
  await fsp3.chmod(parent, 448);
  const tmp = `${p}.tmp.${process.pid}.${Date.now()}.${Math.random().toString(36).slice(2)}`;
  const body = JSON.stringify(state);
  try {
    const fh = await fsp3.open(tmp, "w", 384);
    try {
      await fh.writeFile(body, "utf8");
      await fh.chmod(384);
      await fh.sync();
    } finally {
      await fh.close();
    }
    await fsp3.rename(tmp, p);
  } catch (err) {
    await fsp3.unlink(tmp).catch(() => {});
    throw err;
  }
}
function isEnoent3(err) {
  return typeof err === "object" && err !== null && "code" in err && err.code === "ENOENT";
}

// server-src/tools/share_session.ts
var WATCHER_TIP = "Tip: install our macOS app (https://lore.link/docs/overview) to auto-share new sessions in the background.";
var RUNTIME_TO_HARNESS = {
  "claude-code": "claudeCode",
  cowork: "cowork",
  codex: "codex"
};
async function runShareSession(args, opts = {}) {
  try {
    const harness = opts.harness ?? "cowork";
    return await callCloudTool("share_session", { ...args, harness }, opts);
  } catch (err) {
    if (err instanceof AuthRequiredError) {
      return authRequiredToMcpError();
    }
    throw err;
  }
}
async function shareSessionFromDisk(args, opts = {}) {
  const source = opts.source ?? detectSource(opts.env);
  const env = opts.env ?? process.env;
  const session = runReadLocalSession({
    source,
    args: { session_id: args.session_id },
    env
  });
  const highlight = args.highlight?.trim();
  const title = args.title?.trim();
  const result = await runShareSession({
    transcript: session.transcript,
    uploads: session.uploads,
    outputs: session.outputs,
    ...highlight ? { highlight } : {},
    ...title ? { title } : {}
  }, { fetchImpl: opts.fetchImpl, home: opts.home, harness: RUNTIME_TO_HARNESS[source.runtime] ?? source.runtime });
  if (result.isError === true) {
    return result;
  }
  const resultWithClipboard = await attachClipboardStatus(result, opts.copyToClipboard ?? copyToClipboard);
  let tipText = null;
  try {
    const state = await readPluginState(opts.home);
    const showTip = state.share_count < 3;
    await writePluginState({ ...state, share_count: state.share_count + 1 }, opts.home);
    if (showTip) {
      tipText = WATCHER_TIP;
    }
  } catch (err) {
    console.error("[lore-plugin] warning: failed to update plugin state:", err.message);
  }
  if (tipText === null) {
    return resultWithClipboard;
  }
  return {
    ...resultWithClipboard,
    content: [
      ...resultWithClipboard.content,
      { type: "text", text: tipText }
    ]
  };
}
async function attachClipboardStatus(result, copier) {
  let payload;
  try {
    payload = JSON.parse(result.content[0].text);
  } catch {
    throw new Error("cloud share_session result was not valid JSON");
  }
  const parsed = mcpShareSessionResultSchema.safeParse(payload);
  if (!parsed.success) {
    throw new Error("cloud share_session result did not match its contract");
  }
  let clipboardCopied = false;
  try {
    clipboardCopied = await copier(parsed.data.thread_url);
  } catch {
    clipboardCopied = false;
  }
  const pluginResult = mcpShareSessionPluginResultSchema.parse({
    ...parsed.data,
    clipboard_copied: clipboardCopied
  });
  return {
    ...result,
    content: [
      { ...result.content[0], text: JSON.stringify(pluginResult) },
      ...result.content.slice(1)
    ]
  };
}
var shareSessionTool = {
  name: mcpShareSessionPluginToolSpec.name,
  description: mcpShareSessionPluginToolSpec.description,
  inputSchema: mcpShareSessionPluginToolSpec.inputSchema,
  handler: async (args) => {
    return shareSessionFromDisk(args ?? {});
  }
};

